import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { User, GraduationCap, Shield } from 'lucide-react';

const UnifiedLogin = () => {
  const [selectedPortal, setSelectedPortal] = useState('');
  const navigate = useNavigate();

  const portals = [
    {
      id: 'student',
      title: 'Student Portal',
      description: 'Access your academic records, view violations, and manage your profile',
      icon: GraduationCap,
      color: 'from-orange-500 to-orange-600',
      hoverColor: 'hover:from-orange-600 hover:to-orange-700'
    },
    {
      id: 'teacher',
      title: 'Teacher Portal', 
      description: 'Manage student records, encode violations, and track academic progress',
      icon: User,
      color: 'from-gray-700 to-gray-800',
      hoverColor: 'hover:from-gray-800 hover:to-gray-900'
    },
    {
      id: 'admin',
      title: 'Admin Portal',
      description: 'System administration, user management, and comprehensive oversight',
      icon: Shield,
      color: 'from-black to-gray-800',
      hoverColor: 'hover:from-gray-900 hover:to-black'
    }
  ];

  const handlePortalSelect = (portalId) => {
    setSelectedPortal(portalId);
    setTimeout(() => {
      navigate(`/${portalId}/login`);
    }, 300);
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-black via-gray-900 to-black flex items-center justify-center p-4">
      {/* Background Pattern */}
      <div className="absolute inset-0 opacity-10">
        <div className="absolute inset-0" style={{
          backgroundImage: `radial-gradient(circle at 2px 2px, rgba(251, 146, 60, 0.3) 1px, transparent 1px)`,
          backgroundSize: '40px 40px'
        }}></div>
      </div>

      {/* Main Content */}
      <div className="relative z-10 w-full max-w-6xl">
        {/* Header */}
        <div className="text-center mb-16">
          <h1 className="text-6xl font-bold text-white mb-4">
            <span className="bg-gradient-to-r from-orange-500 to-orange-600 bg-clip-text text-transparent">
              CCS
            </span>
            <span className="text-white"> Management</span>
          </h1>
          <p className="text-xl text-gray-300 mb-2">College of Computer Studies</p>
          <p className="text-gray-400">Select your portal to access the system</p>
        </div>

        {/* Portal Selection Grid */}
        <div className="grid md:grid-cols-3 gap-8 mb-12">
          {portals.map((portal) => {
            const Icon = portal.icon;
            return (
              <button
                key={portal.id}
                onClick={() => handlePortalSelect(portal.id)}
                className={`
                  relative group p-8 rounded-2xl transition-all duration-300 transform
                  ${selectedPortal === portal.id ? 'scale-105' : 'hover:scale-105'}
                  ${portal.hoverColor}
                  bg-gradient-to-br ${portal.color}
                  shadow-2xl hover:shadow-3xl
                  border border-gray-700 hover:border-orange-500
                  overflow-hidden
                `}
              >
                {/* Background Glow */}
                <div className="absolute inset-0 bg-gradient-to-r from-orange-500/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300"></div>

                {/* Content */}
                <div className="relative z-10 text-center">
                  <div className="inline-flex items-center justify-center w-20 h-20 bg-white/10 backdrop-blur-sm rounded-full mb-6 group-hover:bg-white/20 transition-colors duration-300">
                    <Icon className="w-10 h-10 text-white" />
                  </div>

                  <h3 className="text-2xl font-bold text-white mb-3">
                    {portal.title}
                  </h3>

                  <p className="text-gray-200 text-sm leading-relaxed">
                    {portal.description}
                  </p>

                  {/* Selection Indicator */}
                  {selectedPortal === portal.id && (
                    <div className="mt-6 flex items-center justify-center">
                      <div className="w-6 h-6 bg-orange-500 rounded-full flex items-center justify-center">
                        <div className="w-2 h-2 bg-white rounded-full"></div>
                      </div>
                    </div>
                  )}
                </div>

                {/* Hover Effect Border */}
                <div className="absolute inset-0 rounded-2xl bg-gradient-to-r from-orange-500/50 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300"></div>
              </button>
            );
          })}
        </div>

        {/* Footer Info */}
        <div className="text-center">
          <div className="inline-flex items-center space-x-8 text-gray-400 text-sm">
            <div className="flex items-center space-x-2">
              <div className="w-2 h-2 bg-orange-500 rounded-full"></div>
              <span>Secure Login</span>
            </div>
            <div className="flex items-center space-x-2">
              <div className="w-2 h-2 bg-green-500 rounded-full"></div>
              <span>Active System</span>
            </div>
            <div className="flex items-center space-x-2">
              <div className="w-2 h-2 bg-blue-500 rounded-full"></div>
              <span>Multi-Role Access</span>
            </div>
          </div>
        </div>

        {/* Quick Access Info */}
        <div className="mt-12 text-center">
          <p className="text-gray-500 text-sm mb-4">Default Credentials</p>
          <div className="flex flex-wrap justify-center gap-4 text-xs">
            <div className="bg-gray-800/50 backdrop-blur-sm px-3 py-2 rounded-lg border border-gray-700">
              <span className="text-orange-400">Admin:</span> admin / admin123
            </div>
            <div className="bg-gray-800/50 backdrop-blur-sm px-3 py-2 rounded-lg border border-gray-700">
              <span className="text-gray-400">Student:</span> [Student ID] / password
            </div>
            <div className="bg-gray-800/50 backdrop-blur-sm px-3 py-2 rounded-lg border border-gray-700">
              <span className="text-gray-400">Teacher:</span> email / password
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default UnifiedLogin;
